CREATE TABLE IF NOT EXISTS removal_projects (id TEXT PRIMARY KEY, name TEXT NOT NULL, description TEXT, type TEXT NOT NULL, methodology TEXT, "startYear" INTEGER NOT NULL, "endYear" INTEGER, "tCO2eRemovedPerYear" DOUBLE PRECISION NOT NULL, "verificationBody" TEXT, status TEXT NOT NULL DEFAULT 'ACTIVE', notes TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW(), "updatedAt" TIMESTAMP NOT NULL DEFAULT NOW(), "companyId" TEXT NOT NULL REFERENCES companies(id) ON DELETE CASCADE);
